"use client";

import Image from "next/image";
import Link from "next/link";
import { Chart1 } from "@/components/beste/piece/chart1";
import { Stats5 } from "@/components/beste/piece/stats5";
import { Terminal1 } from "@/components/beste/piece/terminal1";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type ComponentBackground =
  | { type: "dots" }
  | { type: "none" }
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string };

type CardMedia =
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string }
  | {
      type: "component";
      component: React.ReactNode;
      background?: ComponentBackground;
    };

interface FeatureCard {
  eyebrow: string;
  title: string;
  description: string;
  media: CardMedia;
}

interface ButtonItem {
  label: string;
  href?: string;
  variant?:
    | "default"
    | "secondary"
    | "outline"
    | "ghost"
    | "link"
    | "destructive";
}

interface Feature194Props {
  badge?: {
    label: string;
    variant?: "default" | "secondary" | "outline";
  };
  heading?: string;
  description?: string;
  cards?: FeatureCard[];
  buttons?: ButtonItem[];
  className?: string;
}

export const feature194Demo: Feature194Props = {
  badge: { label: "Built for builders", variant: "secondary" },
  heading: "Ship faster, measure everything",
  description:
    "A toolkit that meets your team where it works — analytics in the dashboard, wins in the changelog, install in the terminal.",
  cards: [
    {
      eyebrow: "Analytics",
      title: "Insights you trust",
      description:
        "Live dashboards with the metrics that matter. No SQL required, no waiting for a data team.",
      media: {
        type: "component",
        component: (
          <Chart1
            label="Sessions · this week"
            value="8,214"
            data={[42, 68, 54, 81, 36, 72, 90]}
            tone="primary"
          />
        ),
      },
    },
    {
      eyebrow: "Performance",
      title: "Wins worth shipping",
      description:
        "Every release ships with measurable improvements. Track regressions before they reach customers.",
      media: {
        type: "component",
        component: (
          <Stats5
            label="Page load time"
            before="3.4s"
            after="0.8s"
            beforeCaption="Before"
            afterCaption="After"
          />
        ),
      },
    },
    {
      eyebrow: "Developer experience",
      title: "One command away",
      description:
        "Install in seconds with our CLI. Type-safe, framework-aware, no lock-in to anyone's stack.",
      media: {
        type: "component",
        background: {
          type: "image",
          src: "https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=900&fit=crop",
          alt: "Developer workspace with code on screen",
        },
        component: (
          <Terminal1
            prompt="$"
            command="npx beste-ui@latest add feature194"
          />
        ),
      },
    },
  ],
  buttons: [
    { label: "Read the docs", href: "https://beste.co/docs" },
    {
      label: "View on GitHub",
      href: "https://github.com/beste-co",
      variant: "outline",
    },
  ],
};

export function Feature194({
  badge,
  heading,
  description,
  cards = [],
  buttons = [],
  className,
}: Feature194Props) {
  return (
    <section className={cn("py-16 md:py-24", className)}>
      <div className="mx-auto max-w-6xl px-4 md:px-6">
        {(badge || heading || description) && (
          <div className="mx-auto mb-10 md:mb-14 max-w-3xl text-center">
            {badge && (
              <div className="mb-4 flex justify-center">
                <Badge variant={badge.variant ?? "default"}>
                  {badge.label}
                </Badge>
              </div>
            )}
            {heading && (
              <h2 className="text-3xl font-semibold md:text-5xl">{heading}</h2>
            )}
            {description && (
              <p className="mt-4 text-base md:text-lg text-muted-foreground">
                {description}
              </p>
            )}
          </div>
        )}

        <div className="grid gap-4 md:gap-6 md:grid-cols-3">
          {cards.map((card, index) => (
            <div
              key={index}
              className="flex flex-col overflow-hidden rounded-xl border bg-card"
            >
              <CardMediaSurface media={card.media} />
              <div className="flex flex-1 flex-col p-6">
                <span className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
                  {card.eyebrow}
                </span>
                <h3 className="mt-2 text-lg font-semibold">{card.title}</h3>
                <p className="mt-2 text-sm text-muted-foreground">
                  {card.description}
                </p>
              </div>
            </div>
          ))}
        </div>

        {buttons.length > 0 && (
          <div className="mt-12 flex flex-wrap justify-center gap-3">
            {buttons.map((button, index) => (
              <Button
                key={index}
                variant={button.variant ?? "default"}
                asChild
              >
                <Link href={button.href ?? "#"}>{button.label}</Link>
              </Button>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

function CardMediaSurface({ media }: { media: CardMedia }) {
  const componentBackground =
    media.type === "component" ? media.background ?? { type: "dots" } : null;
  const showDots = componentBackground?.type === "dots";

  return (
    <div
      className="relative flex aspect-[4/3] items-center justify-center overflow-hidden border-b bg-muted/30"
      style={
        showDots
          ? {
              backgroundImage:
                "radial-gradient(circle, var(--border) 1px, transparent 1px)",
              backgroundSize: "16px 16px",
            }
          : undefined
      }
    >
      {componentBackground?.type === "image" && (
        <Image
          src={componentBackground.src}
          alt={componentBackground.alt ?? ""}
          fill
          className="object-cover"
          aria-hidden="true"
        />
      )}
      {componentBackground?.type === "video" && (
        <video
          src={componentBackground.src}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 size-full object-cover"
        />
      )}

      {media.type === "video" ? (
        <video
          src={media.src}
          autoPlay
          loop
          muted
          playsInline
          aria-label={media.alt}
          className="size-full object-cover"
        />
      ) : media.type === "image" ? (
        <Image
          src={media.src}
          alt={media.alt ?? ""}
          fill
          className="object-cover"
        />
      ) : (
        <div className="relative flex size-full items-center justify-center">
          {media.component}
        </div>
      )}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

type Tone = "primary" | "foreground" | "success" | "muted";

interface Chart1Props {
  label?: string;
  value?: string;
  data?: number[];
  tone?: Tone;
  className?: string;
}

const toneClasses: Record<Tone, string> = {
  primary: "bg-primary",
  foreground: "bg-foreground",
  success: "bg-emerald-500",
  muted: "bg-muted-foreground",
};

export const chart1Demo: Chart1Props = {
  label: "Sessions · this week",
  value: "8,214",
  data: [42, 68, 54, 81, 36, 72, 90],
  tone: "primary",
};

export function Chart1({
  label,
  value,
  data = [],
  tone = "primary",
  className,
}: Chart1Props) {
  const max = data.length > 0 ? Math.max(...data, 1) : 1;

  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-52 flex-col gap-2 rounded-lg border border-border bg-card px-3 py-2.5 shadow-sm">
        <div className="flex items-baseline justify-between">
          <span className="text-xs font-medium text-muted-foreground">
            {label}
          </span>
          <span className="text-sm font-semibold tabular-nums text-card-foreground">
            {value}
          </span>
        </div>
        <div
          className="flex h-10 items-end gap-1"
          aria-hidden="true"
        >
          {data.map((d, i) => (
            <span
              key={i}
              className={cn(
                "flex-1 rounded-sm transition-all",
                toneClasses[tone]
              )}
              style={{ height: `${Math.max(6, (d / max) * 100)}%` }}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import { ArrowRight } from "lucide-react";
import { cn } from "@/lib/utils";

interface Stats5Props {
  label?: string;
  before?: string;
  after?: string;
  beforeCaption?: string;
  afterCaption?: string;
  className?: string;
}

export const stats5Demo: Stats5Props = {
  label: "Page load time",
  before: "3.4s",
  after: "0.8s",
  beforeCaption: "Before",
  afterCaption: "After",
};

export function Stats5({
  label,
  before = "0",
  after = "0",
  beforeCaption = "Before",
  afterCaption = "After",
  className,
}: Stats5Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-fit max-w-64 flex-col gap-2 rounded-lg border border-border bg-card px-3 py-3 shadow-sm">
        {label && (
          <span className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
            {label}
          </span>
        )}
        <div className="flex items-center gap-3">
          <div className="flex flex-col">
            <span className="text-xs text-muted-foreground">
              {beforeCaption}
            </span>
            <span className="text-xl font-semibold tabular-nums text-muted-foreground line-through">
              {before}
            </span>
          </div>
          <ArrowRight
            className="size-4 shrink-0 text-muted-foreground"
            aria-hidden="true"
          />
          <div className="flex flex-col items-end">
            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400">
              {afterCaption}
            </span>
            <span className="text-xl font-bold tabular-nums text-emerald-600 dark:text-emerald-400">
              {after}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

interface Terminal1Props {
  prompt?: string;
  command?: string;
  className?: string;
}

export const terminal1Demo: Terminal1Props = {
  prompt: "$",
  command: "npx beste-ui@latest init",
};

export function Terminal1({
  prompt = "$",
  command,
  className,
}: Terminal1Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-64 items-center gap-2 rounded-lg border border-zinc-800 bg-zinc-950 px-3 py-2.5 font-mono text-xs text-zinc-50 shadow-sm">
        <span className="shrink-0 text-emerald-400">{prompt}</span>
        <span className="flex-1 truncate">{command}</span>
        <span
          className="h-3.5 w-1.5 shrink-0 animate-pulse bg-emerald-400"
          aria-hidden="true"
        />
      </div>
    </div>
  );
}
